  ('dietitian-moex-05663', 'dietitian', 'dietitian-moex-108-ad4b6c8a', 'sub-dietitian-02', NULL, 'single_choice', '依食品業者專門職業或技術證照人員設置及管理辦法，食品業者應依其類別置專任之技術證照人 員，其中承攬機構餐飲、供應學校餐飲、中央廚房式之餐飲業者，所聘用調理等從業人員的技術 證照比率（%），依序為：', '["65、65、70", "70、70、65", "70、75、75", "75、75、70"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:41+00:00", "source_pdf_sha1": "80fec2c601f4", "answer_pdf_sha1": "bb6dd95cb635", "source_family": "moex-gov-tw", "moex": {"exam_code": "108110", "c": "103", "s": "0204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "團體膳食設計與管理", "year": "108", "exam_name": "108年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、108年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 40, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL)
